#include <bits/stdc++.h>
using namespace std;
vector<int> g[21][2];//g[x][0]表示连接的点，g[x][1]表示长度
int n,m,mark[21];
int dfs(int x){
    int ans=0;
    for(int i=0;i<g[x][0].size();i++){//遍历
        if(mark[g[x][0][i]]){
            mark[g[x][0][i]]=0;
            ans=max(ans,g[x][1][i]+dfs(g[x][0][i]));
            mark[g[x][0][i]]=1;//别忘了回溯
        }
    }
    return ans;
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=m;i++){
        int x,y,z;
        cin>>x>>y>>z;
        g[x][0].push_back(y);
        g[y][0].push_back(x);
        g[x][1].push_back(z);
        g[y][1].push_back(z);
    }
    int ans=0;
    for(int i=1;i<=n;i++){
        memset(mark,1,sizeof(mark));
        mark[i]=0;
        ans=max(dfs(i),ans);
        //遍历每个结点为起点进行搜索，选出最长路径
    }
    cout<<ans;
    return 0;
}
